var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"부, 부사장님. 보고드립니다.","JPN":"ふ、副社長。ご報告いたします。","ENG":"V-vice President... I have some bad news to report.","TWN":"報…報告副總。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"조금 전 발생한 강력한 폭발과 함께…… 힐데 소대장님의 신호가 사라졌습니다.","JPN":"先ほど発生した強力な爆発とともに……ヒルデ小隊長の信号が途絶えました。","ENG":"Following the massive explosion just before, Commander Hilde's signal has vanished.","TWN":"剛才發生強烈爆炸後……就沒看到希爾德小隊長的信號。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……당했군요.","JPN":"……やられましたね。","ENG":"...They got us.","TWN":"……看來是凶多吉少。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"애초에 스승님이 나설 수밖에 없는 적을 준비해 놓은 것부터 수상했는데.","JPN":"だいたい師匠が出るしかない敵を準備しておいたことから怪しかったですが。","ENG":"It seemed suspicious that they had planned an enemy that only Master could handle.","TWN":"我剛就覺得奇怪，為什麼要派出非得逼師父出馬不可的對手。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 설마 힐데 소대장은 전사한 건가?","JPN":"どういうことだ？　まさかヒルデ小隊長は戦死したのか？","ENG":"What’s going on? Has Commander Hilde fallen?","TWN":"怎麼回事？希爾德小隊長該不會已經戰死沙場？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아뇨. 스승님이 그리 쉽게 죽을 리 없죠.","JPN":"いいえ。師匠がそう簡単に死ぬわけありません。","ENG":"No, Master isn’t one to fall so easily.","TWN":"不，師父沒那麼容易死掉的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아마 균열이 발생한 시점에 전투 중 방출된 에너지로 인해 다른 차원으로 전이되었을 겁니다.","JPN":"多分亀裂が発生した時点で、戦闘中に放出されたエネルギーによって違う次元へと転移させられたはずです。","ENG":"She appears to have been transported to another dimension by the energy released during the battle when the rift opened.","TWN":"應該是產生裂縫當下，由於戰鬥中釋放出的能量而掉到其他次元。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 즉시 복귀할 수 있다는 건가?","JPN":"それならただちに復帰できるということなのか？","ENG":"Does this mean she'll be able to return immediately?","TWN":"那她可以馬上回來嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 돌아오기까지는 시간이 꽤 걸리겠죠.","JPN":"戻ってくるまで結構時間がかかるでしょう。","ENG":"It’ll take some time for her to return to us.","TWN":"回來會需要花很長的時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우린 싸우기도 전에 가장 강력한 무기를 잃은 셈이군요.","JPN":"私たちは戦う前にもっとも強力な武器を失ったことになりますね。","ENG":"So we've effectively lost our trump card even before the battle begins.","TWN":"意思就是我們在開戰前夕，損失一枚最厲害的武器。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그거 곤란하군…….","JPN":"それはまいったな……","ENG":"That is bad news...","TWN":"糟糕……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"실례합니다, 중장님. 척후 임무 중 보고드릴 사안이 생겼어요.","JPN":"失礼いたします、中将。斥候の任務途中、ご報告する事案が発生しました。","ENG":"Excuse my interruption, Lieutenant General. During our recon, we discovered something important that you should be aware of.","TWN":"抱歉，中將，我正在執行偵察任務，有事情要向您報告。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저건…… 리플레이서 퀸의 재생체로군요.","JPN":"あれは……リプレイサー・クイーンの再生体ですね。","ENG":"That’s... the Regenerated Replacer Queen.","TWN":"那是……克隆·女皇的再生體？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"처분하지 않았던 건가요?","JPN":"処分していなかったのですか？","ENG":"You didn’t dispose of her?","TWN":"還沒有處理掉嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"인력난을 겪고 있는 건 우리나 그쪽이나 마찬가지 아닌가?","JPN":"人手不足なのはお互い様ではないか？","ENG":"You're not the only one having difficulty finding personnel.","TWN":"誰叫我們和你們一樣，都在鬧人才荒呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"제이나는 사망한 리플레이서 퀸의 재생체야. 정상참작의 여지가 있지.","JPN":"ジェイナは死亡したリプレイサー・クイーンの再生体だ。情状酌量の余地がある。","ENG":"Jaina is the regenerated form of the deceased Replacer Queen. We determined that there are extenuating circumstances.","TWN":"婕娜是死去克隆·女皇的再生體，她的去留是有討論空間的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"도미닉과 그녀는 분명 잘못된 선택을 했어.","JPN":"ドミニクと彼女は確かに間違った選択をした。","ENG":"Without a doubt, she and Dominic made the wrong decision.","TWN":"多明尼克和她確實是做出錯誤的選擇，"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 그들의 유산이 올바른 곳에 쓰인다면, 두 사람의 선택으로 희생됐던 이들도 조금은 편히 잠들 수 있지 않을까 생각하네.","JPN":"だが彼らの遺産が正しいことに使われるのなら、二人の選択で犠牲になった者も少しは安らかに眠れるのではないかと思っているのだ。","ENG":"We believe, however, that if their legacies are put to good use, their victims will be able to rest a little easier.","TWN":"但若是將他們的遺產運用在正確的事物上，那我想因他們二人而犧牲的人也會感到安慰吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですね。","ENG":"...I see.","TWN":"……原來如此。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아무튼 무슨 일이지, 제이나?","JPN":"それはいいとして、どういうことだ？　ジェイナ。","ENG":"Anyway, what is it, Jaina?","TWN":"婕娜，說吧，什麼事？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"전방에서 대규모 중갑…… 기사단이, 접근 중이에요.","JPN":"前方から大規模の重甲……騎士団が接近しています。","ENG":"A swarm of heavily armored... \\"knights\\" is approaching straight ahead.","TWN":"前方有大規模重裝……騎士團正在接近中。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"곧 함교의 가시거리 내로 진입할 것 같아요.","JPN":"もうすぐ艦橋の可視距離内へ進入しそうです。","ENG":"They should be coming into view from the bridge soon.","TWN":"就快進到艦船的能見範圍內。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"철갑 기사단이라고? 확실한가?","JPN":"重甲騎士団だと？　確かなのか？","ENG":"Armored knights? Are you sure?","TWN":"鐵甲騎士團？你確定嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네. 말씀드리면서도 당황스럽지만……","JPN":"はい。お伝えしながらも困惑していますが……","ENG":"Yes. I can’t believe I’m saying this...","TWN":"對，跟中將報告的同時我也覺得荒謬……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"분명 중세 시대 때나 입었을 것 같은 갑옷을 입고 있었어요.","JPN":"確かに中世時代にあったような鎧を身につけていました。","ENG":"But they are definitely wearing medieval armor.","TWN":"但他們確實身穿類似中世紀的盔甲。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……수고했네. 일단 복귀하게나.","JPN":"……ご苦労だった。とりあえず復帰しろ。","ENG":"...Understood. Return to the ship for now.","TWN":"……辛苦了，你先回來吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저쪽도 우리에게 시간을 줄 생각은 없나 보군요.","JPN":"あちらも私たちに時間を与えないつもりのようですね。","ENG":"It looks like they don’t intend on giving us time to prepare either.","TWN":"看來對方不打算給我們時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어떻게 하실 생각이죠?","JPN":"どうなさいますか？","ENG":"So, what do you plan on doing?","TWN":"你打算怎麼做？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……의외로군. 여기까지 와서 이쪽 방식을 묻는 건가?","JPN":"……意外だな。いまさらこちらのやり方を尋ねるのか？","ENG":"...This is rather unexpected. After coming all this way, you want to know how we'll proceed?","TWN":"……真是意外，這種時候你竟然問我打算怎麼做？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"안타깝게도 구 관리국의 방식은 꽤 과격한 편이라서 말입니다.","JPN":"残念ながら、旧管理局のやり方は結構過激ですので。","ENG":"Unfortunately, the Old Administration’s methods can be extreme.","TWN":"這是因為舊管理局的做法會比較激烈。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님께서 사라진 지금으로서는 실행에 옮기기도 불가능하죠.","JPN":"師匠がいなくなった今は実行することもできません。","ENG":"And with Master unavailable at the moment, we won’t be able to carry them out either.","TWN":"而且我們現在失去師父，也無法有什麼動作。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 여기선 기꺼이 지휘권을 양도하려고 합니다.","JPN":"ですので、ここでは喜んで指揮権を譲るつもりです。","ENG":"Therefore, we'd like to entrust operational command to Delta Seven.","TWN":"所以我現在很樂意將指揮權讓給你。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"우리는 이곳 좌표에 끌려와서 장소를 빼앗겼고, 이제는 적을 공격할 시기까지 빼앗겼어.","JPN":"我々はこの座標に引っ張られては場所を奪われ、今は敵を攻撃する時期まで奪われた。","ENG":"We were dragged to these coordinates, and as a result, we lost control of the environment and the offensive initiative.","TWN":"我們被帶到這個座標來，失去我們的據點，現在又錯失進攻敵人的時機。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그쪽이 가장 강력한 무기까지 잃었다고 했으니 필패의 조건을 모두 갖춘 셈이지.","JPN":"そちらはもっとも強力な武器まで失ったということだから、必ず負ける条件はすべて揃ったわけだ。","ENG":"Furthermore, you say that you have lost your most powerful weapon. We’ve fulfilled all of the conditions for total defeat.","TWN":"你們則是失去最強的武器，現在的我們等於毫無勝算。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그러니 먼저 우리에게 유리한 전장부터 조성해야겠군.","JPN":"ゆえにまず我々に有利な戦場から作るべきだな。","ENG":"Therefore, our first step should be to turn the tide in our favor.","TWN":"因此我想現在當務之急，就是打造出對我們有利的戰場。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"호오, 어떻게 말인가요?","JPN":"ほう、どうやってですか？","ENG":"Oh? How do we do that?","TWN":"喔呵，要怎麼做呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"간단하지. 퇴각일세.","JPN":"簡単だ。退却するのだ。","ENG":"It’s simple. We retreat.","TWN":"很簡單，就是撤退。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하, 적들이 물러나고 있습니다.","JPN":"殿下、敵が退却しています。","ENG":"The enemy is retreating, Your Highness.","TWN":"殿下，敵人撤退中。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"설마 우리를 두려워하는 걸까요?","JPN":"もしかして私たちを恐れているのでしょうか？","ENG":"Are they afraid of us?","TWN":"是怕我們嗎？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"발키리를 잃었다고 겁에 질려 도망칠 자들이었으면 애초에 여기 왔을 리 없지.","JPN":"ヴァルキリーを失ったと怯えて逃げる者たちだったら、最初からここへ来なかったはずだ。","ENG":"They wouldn't have come here if they were the type to flee with their tails between their legs because they had lost the Valkyrie.","TWN":"若他們會因為失去女武神就落荒而逃，那我們根本就不需要到這裡來。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"자만과 분노에 취해 정면으로 부딪쳐 오길 기대했건만……","JPN":"自慢と怒りに酔い、真正面からぶつかってくることを期待していたが……","ENG":"I had hoped that they would meet us head-on, blinded by arrogance and rage.","TWN":"雖然我原本是期待他們會陷入驕傲與憤怒之中，然後來個正面對決……"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저들의 지휘관도 제법 노련한 자인가 보군.","JPN":"あちらの指揮官もなかなかの手練れのようだな。","ENG":"It seems that their commander is quite experienced.","TWN":"不過看來他們的指揮官蠻努力的。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어떻게 하시겠습니까, 전하.","JPN":"どうなさいますか、殿下。","ENG":"Your orders, Your Highness?","TWN":"殿下，您打算怎麼做？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"적들이 물러서기를 원하면 추격해 주는 것이 전장의 예의범절이다.","JPN":"敵が退くことを望んでいるなら、追撃するのが戦場の礼儀であろう。","ENG":"Pursuing an enemy that wishes to retreat is battlefield etiquette.","TWN":"既然敵人想要撤退，那追上去應該是基本的戰場禮儀吧？"},"stage":{"bg":"MS_903","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 공, 그대에게 선봉을 맡기겠다!","JPN":"マルチネス公、そなたに先鋒を任せよう！","ENG":"Marquise Martinez., you have command of the vanguard!","TWN":"馬汀尼茲侯爵，我命你為先鋒！"},"stage":{"bg":"MS_903","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"상대의 꼬리를 물어뜯도록!","JPN":"相手の尻尾を噛みちぎれ！","ENG":"Hunt them down!","TWN":"緊咬著他們的尾巴不放！"},"stage":{"bg":"MS_903","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};